def parse_frontmatter(text: str) -> tuple[str, str]:
    text = text.lstrip("\ufeff")
    if not text.startswith("---\n"):
        return "", text
    end = text.find("\n---\n", 4)
    if end == -1:
        return "", text
    return text[4:end], text[end + 5 :]


def find_insert_offset(body: str) -> int:
    anchors = ("問題背景", "裝置與方法", "核心分析", "常見誤解", "相關概念", "延伸價值")
    for match in SECTION_RE.finditer(body):
        heading = match.group(2).strip()
        if any(keyword in heading for keyword in anchors):
            return match.start()
    return len(body)


def ensure_sections(body: str, intuition: str, history: str) -> tuple[str, bool]:
    has_intuition = f"## {INTUITION_HEADING}" in body
    has_history = f"## {HISTORY_HEADING}" in body
    if has_intuition and has_history:
        return body, False
    blocks: list[str] = []
    if not has_intuition:
        blocks.append(f"## {INTUITION_HEADING}\n{intuition}\n")
    if not has_history:
        blocks.append(f"## {HISTORY_HEADING}\n{history}\n")
    insertion = "\n".join(blocks).strip() + "\n\n"
    offset = find_insert_offset(body)
    updated = body[:offset].rstrip() + "\n\n" + insertion + body[offset:].lstrip()
    return updated, True


def process_path(vault: Path, relative_path: str) -> bool:
    path = vault / relative_path
    text = path.read_text(encoding="utf-8")
    raw_frontmatter, body = parse_frontmatter(text)
    if relative_path in MAP_TEXT:
        payload = MAP_TEXT[relative_path]
    else:
        payload = EXPERIMENT_TEXT[relative_path]
    new_body, changed = ensure_sections(body, payload["intuition"], payload["history"])
    if not changed:
        return False
    final = f"---\n{raw_frontmatter}\n---\n{new_body}" if raw_frontmatter else new_body
    path.write_text(final, encoding="utf-8")
    return True


def main() -> None:
    parser = argparse.ArgumentParser(description="Fill missing standard sections for a single map or experiment note.")
    parser.add_argument("relative_path", help="Vault-relative note path")
    args = parser.parse_args()
    vault = resolve_vault_path()
    changed = process_path(vault, args.relative_path)
    print(f"changed={1 if changed else 0}")


if __name__ == "__main__":
    main()
